queries.sparql:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasEquipment ?child ; p:hasLabs ?parent . } GROUP BY ?child }
  ?child p:type ?type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Labs } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?type WHERE {
  ?labs_equipment a :Labs_Equipment .
  ?equipment a :Equipment .
  ?labs_equipment p:hasEquipment ?equipment .
  ?labs a :Labs .
  ?labs_equipment p:hasLabs ?labs .
  ?labs p:name ?name .
  ?equipment p:type ?type .
} }
  collective: { SELECT ?type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasEquipment ?child ; p:hasLabs ?parent . } GROUP BY ?child }
  ?child p:type ?type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Labs } }
  FILTER(?nf = ?total)
} }
}
